function customSVG(options, svgString) {
  const { colors: colors2 = [], width, height, size: size2, raw = false } = options;
  const widthMatch = svgString.match(/width="[^"]*"/);
  const heightMatch = svgString.match(/height="[^"]*"/);
  const finalWidth = size2 || width || widthMatch?.[1] || "100";
  const finalHeight = size2 || height || heightMatch?.[1] || "100";
  if (width || height || size2) {
    svgString = svgString.replace(/width="[^"]*"/, `width="${finalWidth}px"`);
    svgString = svgString.replace(/height="[^"]*"/, `height="${finalHeight}px"`);
  }
  if (colors2 && colors2.length > 0) {
    const hexColorRegex = /#[0-9a-fA-F]{6}|#[0-9a-fA-F]{3}/g;
    let colorIndex = 0;
    svgString = svgString.replace(hexColorRegex, (match) => {
      if (colorIndex < colors2.length) {
        const replacement = colors2[colorIndex];
        colorIndex++;
        return replacement?.startsWith("#") ? replacement : `#${replacement}`;
      }
      return match;
    });
  }
  if (!raw)
    svgString = (width || height || size2 ? `<img width="${finalWidth}" height="${finalHeight}"` : "<img") + ` alt="icon" src="data:image/svg+xml;utf8,${encodeURIComponent(svgString)}" />`;
  return svgString;
}
